namespace sv_828fa9f0236a4b339d6d95c9f7f4fd9b.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend.
/// </summary>
public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-1001"] = new Shipment
        {
            TrackingNumber = "TRK-1001",
            Status = "In Transit",
            Location = "Memphis, TN",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 2, 17, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 24, 8, 0, 0, TimeSpan.Zero), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 24, 22, 15, 0, TimeSpan.Zero), Description = "Arrived at sorting facility — Memphis, TN" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 6, 30, 0, TimeSpan.Zero), Description = "In transit to destination" },
            ]
        },
        ["TRK-2002"] = new Shipment
        {
            TrackingNumber = "TRK-2002",
            Status = "Delivered",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 20, 12, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 17, 10, 0, 0, TimeSpan.Zero), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 18, 14, 0, 0, TimeSpan.Zero), Description = "Arrived at regional hub — Portland, OR" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 19, 9, 45, 0, TimeSpan.Zero), Description = "Out for delivery" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 19, 14, 20, 0, TimeSpan.Zero), Description = "Delivered — signed by J. Smith" },
            ]
        },
        ["TRK-3003"] = new Shipment
        {
            TrackingNumber = "TRK-3003",
            Status = "Processing",
            Location = "Austin, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 17, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 16, 0, 0, TimeSpan.Zero), Description = "Order placed — awaiting pickup" },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);
        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_828fa9f0236a4b339d6d95c9f7f4fd9b.Client.Models
@using sv_828fa9f0236a4b339d6d95c9f7f4fd9b.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

<h3>Shipment Tracking</h3>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <span class="spinner-border spinner-border-sm me-2" aria-hidden="true"></span>
        Loading shipment <strong>@TrackingNumber</strong>&hellip;
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning" role="alert">
        No shipment found for tracking number <strong>@TrackingNumber</strong>.
    </div>
}
else
{
    <div class="card mb-3">
        <div class="card-body">
            <h5 class="card-title">@_shipment.TrackingNumber</h5>
            <p><strong>Status:</strong> @_shipment.Status</p>
            <p><strong>Location:</strong> @_shipment.Location</p>
            @if (_shipment.EstimatedDelivery.HasValue)
            {
                <p><strong>Estimated Delivery:</strong> @_shipment.EstimatedDelivery.Value.ToString("f")</p>
            }
        </div>
    </div>

    @if (_shipment.Updates.Count > 0)
    {
        <h5>Status Updates</h5>
        <ul class="list-group">
            @foreach (var update in _shipment.Updates)
            {
                <li class="list-group-item">
                    <strong>@update.Timestamp.ToString("g")</strong> &mdash; @update.Description
                </li>
            }
        </ul>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request (handles parameter changes while loading).
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Request was intentionally cancelled — do nothing.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please check your connection and try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please check your connection and try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

